import React from 'react';
import { motion } from 'framer-motion';

const Footer = () => {
  return (
    <motion.footer
      initial={{ opacity: 0, y: 60 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6 }}
      viewport={{ once: true }}
      className="mt-20 border-t border-white/10 bg-[#080e1a]/90 backdrop-blur-xl"
    >
      <div className="max-w-7xl mx-auto px-6 py-12 flex flex-wrap gap-10">

        {/* Brand */}
        <div className="flex-1 min-w-[220px] space-y-3">
          <div className="flex items-center gap-2 group cursor-pointer">
            <motion.div
              whileHover={{ rotate: 15, scale: 1.1 }}
              className="flex h-10 w-10 items-center justify-center rounded-xl bg-amber-500/10 text-amber-400"
            >
              ⬡
            </motion.div>
            <span className="text-lg font-bold text-amber-400 tracking-wide">
              HostelMate
            </span>
          </div>

          <p className="text-sm text-slate-400">
            Smart Hostel Management System
          </p>

          <p className="text-xs text-slate-500">
            © 2025 HostelMate. All rights reserved.
          </p>
        </div>

        {/* Contact */}
        <div className="flex-1 min-w-[180px] space-y-3">
          <h5 className="text-xs uppercase tracking-widest text-slate-300 font-semibold">
            Contact
          </h5>

          <p className="text-sm text-slate-400 hover:text-white transition">
            kuldeepkh1305@gmail.com
          </p>

          <p className="text-sm text-slate-400 hover:text-white transition">
            +91-8433202325
          </p>

          <div className="flex gap-4 pt-2">
            {[
              { href: 'https://www.linkedin.com/in/kuldeepkh1305/', label: 'LinkedIn' },
              { href: 'https://github.com/kuldeep1306', label: 'GitHub' },
            ].map(({ href, label }) => (
              <motion.a
                key={href}
                href={href}
                target="_blank"
                rel="noreferrer"
                whileHover={{ y: -2, scale: 1.05 }}
                className="text-sm text-slate-400 hover:text-amber-400 transition"
              >
                {label}
              </motion.a>
            ))}
          </div>
        </div>

        {/* About */}
        <div className="flex-1 min-w-[180px] space-y-3">
          <h5 className="text-xs uppercase tracking-widest text-slate-300 font-semibold">
            About
          </h5>

          <p className="text-sm text-slate-400">
            Developed by <span className="text-white font-medium">Kuldeep Sharma</span>
          </p>

          <p className="text-sm italic text-slate-500">
            "Making hostel life easier!"
          </p>
        </div>
      </div>

      {/* Divider */}
      <div className="h-px bg-white/10 max-w-7xl mx-auto" />

      {/* Bottom */}
      <motion.p
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
        transition={{ delay: 0.2 }}
        className="text-center text-xs text-slate-500 py-4"
      >
        RKGIT Hostel Portal — Ghaziabad, Uttar Pradesh
      </motion.p>
    </motion.footer>
  );
};

export default Footer;
